"use client";

import { TrendingUp } from "lucide-react";

import { Map, MapGeoJSON, MapMarker, MarkerContent } from "@/components/ui/map";
import { Button } from "@/components/ui/button";
import { totalVisitors, visitorGrowth, visitorLocations } from "./data";

// Country borders from a public CDN, or swap in your own GeoJSON.
const WORLD_GEOJSON =
  "https://cdn.jsdelivr.net/gh/nvkelso/natural-earth-vector@v5.1.2/geojson/ne_110m_admin_0_countries.geojson";

function bubbleSize(visitors: number) {
  return Math.round(10 + Math.sqrt(visitors) * 2.2);
}

export default function Page() {
  return (
    <div className="flex min-h-screen items-center justify-center p-8">
      <div className="bg-card relative aspect-16/10 w-full max-w-md overflow-hidden rounded-xl border shadow-sm">
        <div className="absolute inset-0">
          <Map
            center={[1, 30]}
            scrollZoom={false}
            dragRotate={false}
            dragPan={false}
            doubleClickZoom={false}
            pitchWithRotate={false}
            blank
          >
            <MapGeoJSON data={WORLD_GEOJSON} linePaint={false} />
            {visitorLocations.map((location) => {
              const size = bubbleSize(location.visitors);
              return (
                <MapMarker
                  key={location.city}
                  longitude={location.lng}
                  latitude={location.lat}
                >
                  <MarkerContent className="cursor-default">
                    <span
                      className="bg-chart-2/80 block rounded-full"
                      style={{ width: size, height: size }}
                    />
                  </MarkerContent>
                </MapMarker>
              );
            })}
          </Map>
        </div>

        <div
          className="from-card to-card/0 pointer-events-none absolute inset-x-0 top-0 z-10 h-24 rounded-t-xl bg-linear-to-b [mask-image:linear-gradient(to_bottom,black_55%,transparent)] backdrop-blur-[2px]"
          aria-hidden
        />

        <div className="relative z-20 flex items-start justify-between gap-3 p-4">
          <div>
            <h2 className="text-foreground text-lg font-medium tracking-tight">
              Analytics
            </h2>
            <div className="mt-1.5 flex items-center gap-2">
              <p className="text-muted-foreground text-xs font-medium">
                <span className="tabular-nums">{totalVisitors}</span> visitors
              </p>
              <span className="inline-flex items-center gap-0.5 text-xs font-medium">
                <TrendingUp className="size-2.5" />
                {visitorGrowth}
              </span>
            </div>
          </div>

          <Button variant="outline" size="xs" className="h-7 px-2.5">
            View Analytics
          </Button>
        </div>
      </div>
    </div>
  );
}

export interface VisitorLocation {
  city: string;
  lng: number;
  lat: number;
  visitors: number;
}

export const totalVisitors = "418.2K";
export const visitorGrowth = "+10%";

export const visitorLocations: VisitorLocation[] = [
  { city: "San Francisco", lng: -122.4194, lat: 37.7749, visitors: 62 },
  { city: "New York", lng: -74.006, lat: 40.7128, visitors: 58 },
  { city: "Mexico City", lng: -99.1332, lat: 19.4326, visitors: 22 },
  { city: "Sao Paulo", lng: -46.6333, lat: -23.5505, visitors: 30 },
  { city: "London", lng: -0.1276, lat: 51.5074, visitors: 48 },
  { city: "Berlin", lng: 13.405, lat: 52.52, visitors: 28 },
  { city: "Madrid", lng: -3.7038, lat: 40.4168, visitors: 18 },
  { city: "Lagos", lng: 3.3792, lat: 6.5244, visitors: 16 },
  { city: "Dubai", lng: 55.2708, lat: 25.2048, visitors: 24 },
  { city: "Mumbai", lng: 72.8777, lat: 19.076, visitors: 40 },
  { city: "Singapore", lng: 103.8198, lat: 1.3521, visitors: 21 },
  { city: "Tokyo", lng: 139.6917, lat: 35.6895, visitors: 38 },
  { city: "Seoul", lng: 126.978, lat: 37.5665, visitors: 26 },
  { city: "Sydney", lng: 151.2093, lat: -33.8688, visitors: 17 },
];
